import React, { useState, useRef, useEffect } from 'react';
import {
  View,
  Text,
  TouchableOpacity,
  StyleSheet,
  Alert,
  ActivityIndicator,
  Image,
  Dimensions,
  StatusBar,
  Animated
} from 'react-native';
import { CameraView, useCameraPermissions } from 'expo-camera';
import * as ImagePicker from 'expo-image-picker';
import * as Location from 'expo-location';
import { MaterialCommunityIcons, MaterialIcons } from '@expo/vector-icons';
import { detectDisease } from '../services/api';

const { width, height } = Dimensions.get('window');

const DiseaseDetectionScreen = ({ navigation }) => {
  const [permission, requestPermission] = useCameraPermissions();
  const [selectedImage, setSelectedImage] = useState(null);
  const [loading, setLoading] = useState(false);
  const [facing, setFacing] = useState('back');
  const [flash, setFlash] = useState('off');
  const [showTips, setShowTips] = useState(true);
  const cameraRef = useRef(null);
  const scanLineAnim = useRef(new Animated.Value(0)).current;

  useEffect(() => {
    if (!selectedImage && permission?.granted) {
      Animated.loop(
        Animated.sequence([
          Animated.timing(scanLineAnim, {
            toValue: 240,
            duration: 2000,
            useNativeDriver: true,
          }),
          Animated.timing(scanLineAnim, {
            toValue: 0,
            duration: 2000,
            useNativeDriver: true,
          }),
        ])
      ).start();
    }
  }, [selectedImage, permission]);

  const takePicture = async () => {
    if (!cameraRef.current) return;
    try {
      const photo = await cameraRef.current.takePictureAsync({ quality: 0.7 });
      setSelectedImage(photo.uri);
      handleDetect(photo.uri);
    } catch (err) {
      Alert.alert('Error', 'Failed to take picture.');
    }
  };

  const pickFromGallery = async () => {
    const result = await ImagePicker.launchImageLibraryAsync({
      mediaTypes: ImagePicker.MediaTypeOptions.Images,
      quality: 0.7,
      allowsEditing: true,
      aspect: [1, 1]
    });

    if (!result.canceled && result.assets.length > 0) {
      setSelectedImage(result.assets[0].uri);
      handleDetect(result.assets[0].uri);
    }
  };

  const handleDetect = async (uri) => {
    setLoading(true);
    try {
      let lat = null, lng = null;
      try {
        const { status } = await Location.requestForegroundPermissionsAsync();
        if (status === 'granted') {
          const loc = await Location.getCurrentPositionAsync({ accuracy: Location.Accuracy.Balanced });
          lat = loc.coords.latitude;
          lng = loc.coords.longitude;
        }
      } catch (locErr) { }

      const result = await detectDisease(uri, 'maize', lat, lng);
      navigation.navigate('Results', { result, imageUri: uri });
    } catch (err) {
      // Mock result for demo
      const mockResult = {
        detection: {
          id: 'demo-' + Date.now(),
          disease_name: 'Maize Streak Virus',
          confidence: 0.92,
          crop_type: 'maize',
          created_at: new Date().toISOString()
        },
        predictions: [
          { disease_name: 'Maize Streak Virus', confidence: 0.92 },
          { disease_name: 'Grey Leaf Spot', confidence: 0.05 },
          { disease_name: 'Common Rust', confidence: 0.03 }
        ],
        disease_info: {
          symptoms: 'Broken, yellowish to white streaks that run parallel to the leaf veins. Streaks are usually uniform in width and distributed throughout the leaf surface.',
          treatment: '1. Identify and remove infected plants immediately\n2. Apply recommended systemic insecticides\n3. Keep the field clear of grassy weeds',
          prevention: 'Plant resistant maize varieties. Ensure proper spacing and maintain soil health.'
        }
      };
      setTimeout(() => {
        navigation.navigate('Results', { result: mockResult, imageUri: uri });
      }, 1500);
    } finally {
      setLoading(false);
    }
  };

  if (!permission) return <View style={styles.center}><ActivityIndicator color="#2c5926" /></View>;

  return (
    <View style={styles.container}>
      <StatusBar barStyle="light-content" translucent backgroundColor="transparent" />

      {/* Camera Viewfinder */}
      <View style={styles.viewfinderContainer}>
        {!selectedImage && permission.granted ? (
          <CameraView
            ref={cameraRef}
            style={styles.camera}
            facing={facing}
            flash={flash}
          >
            {/* Header Overlay */}
            <View style={styles.headerOverlay}>
              <TouchableOpacity style={styles.roundBtn} onPress={() => navigation.goBack()}>
                <MaterialIcons name="close" size={24} color="#FFF" />
              </TouchableOpacity>
              <View style={styles.headerTitleContainer}>
                <Text style={styles.headerTitle}>Disease Detection</Text>
                <View style={styles.aiStatus}>
                  <View style={styles.aiDot} />
                  <Text style={styles.aiText}>AI ACTIVE</Text>
                </View>
              </View>
              <TouchableOpacity style={styles.roundBtn}>
                <MaterialIcons name="help-outline" size={24} color="#FFF" />
              </TouchableOpacity>
            </View>

            {/* Scanning Guide */}
            <View style={styles.guideContainer}>
              <View style={styles.guideFrame}>
                <View style={[styles.corner, styles.topL]} />
                <View style={[styles.corner, styles.topR]} />
                <View style={[styles.corner, styles.botL]} />
                <View style={[styles.corner, styles.botR]} />

                {/* Animated Scan Line */}
                <Animated.View
                  style={[
                    styles.scanLine,
                    { transform: [{ translateY: scanLineAnim }] }
                  ]}
                />
              </View>
            </View>

            {/* Tips Overlay */}
            {showTips && (
              <View style={styles.tipsContainer}>
                <View style={styles.tipsCard}>
                  <View style={styles.tipsIcon}>
                    <MaterialIcons name="info" size={20} color="#2c5926" />
                  </View>
                  <View style={styles.tipsTextContent}>
                    <Text style={styles.tipsTitle}>Scanning Tips</Text>
                    <Text style={styles.tipsBody}>Ensure good lighting and center the leaf within the frame for high accuracy.</Text>
                  </View>
                  <TouchableOpacity style={styles.gotItBtn} onPress={() => setShowTips(false)}>
                    <Text style={styles.gotItText}>Got it</Text>
                  </TouchableOpacity>
                </View>
              </View>
            )}

            {/* Bottom Controls */}
            <View style={styles.controlsLayer}>
              <View style={styles.controlsRow}>
                <TouchableOpacity style={styles.controlBtn} onPress={pickFromGallery}>
                  <View style={styles.controlIconCircle}>
                    <MaterialIcons name="photo-library" size={24} color="#FFF" />
                  </View>
                  <Text style={styles.controlLabel}>Gallery</Text>
                </TouchableOpacity>

                <TouchableOpacity style={styles.captureOuter} onPress={takePicture}>
                  <View style={styles.captureMiddle}>
                    <View style={styles.captureInner}>
                      <MaterialIcons name="camera-alt" size={32} color="#FFF" />
                    </View>
                  </View>
                </TouchableOpacity>

                <TouchableOpacity
                  style={styles.controlBtn}
                  onPress={() => setFlash(f => f === 'off' ? 'on' : 'off')}
                >
                  <View style={styles.controlIconCircle}>
                    <MaterialIcons
                      name={flash === 'on' ? "flash-on" : "flash-off"}
                      size={24}
                      color="#FFF"
                    />
                  </View>
                  <Text style={styles.controlLabel}>Flash</Text>
                </TouchableOpacity>
              </View>
            </View>

            {/* Bottom Navigation Mockup (matching parity) */}
            <View style={styles.bottomNavOverlay}>
              <TouchableOpacity style={styles.navItem} onPress={() => navigation.navigate('Dashboard')}>
                <MaterialCommunityIcons name="home-outline" size={24} color="rgba(255,255,255,0.6)" />
                <Text style={styles.navText}>Home</Text>
              </TouchableOpacity>
              <TouchableOpacity style={styles.navItem}>
                <MaterialCommunityIcons name="camera" size={24} color="#2c5926" />
                <Text style={[styles.navText, { color: '#2c5926' }]}>Scan</Text>
              </TouchableOpacity>
              <TouchableOpacity style={styles.navItem}>
                <MaterialCommunityIcons name="history" size={24} color="rgba(255,255,255,0.6)" />
                <Text style={styles.navText}>History</Text>
              </TouchableOpacity>
              <TouchableOpacity style={styles.navItem}>
                <MaterialCommunityIcons name="account-outline" size={24} color="rgba(255,255,255,0.6)" />
                <Text style={styles.navText}>Profile</Text>
              </TouchableOpacity>
            </View>
          </CameraView>
        ) : selectedImage ? (
          <View style={styles.fullPreview}>
            <Image source={{ uri: selectedImage }} style={styles.previewImage} />
            <View style={styles.loadingOverlay}>
              <ActivityIndicator size="large" color="#FFF" />
              <Text style={styles.loadingText}>Analyzing Crop...</Text>
            </View>
          </View>
        ) : (
          <View style={styles.permissionBox}>
            <MaterialIcons name="photo-camera" size={64} color="#2c5926" />
            <Text style={styles.permTitle}>Camera Access Needed</Text>
            <Text style={styles.permText}>Allow Murimi to use your camera to scan crops for diseases</Text>
            <TouchableOpacity style={styles.enableBtn} onPress={requestPermission}>
              <Text style={styles.enableBtnText}>Enable Camera</Text>
            </TouchableOpacity>
          </View>
        )}
      </View>
    </View>
  );
};

const styles = StyleSheet.create({
  container: {
    flex: 1,
    backgroundColor: '#000'
  },
  center: {
    flex: 1,
    justifyContent: 'center',
    alignItems: 'center'
  },
  viewfinderContainer: {
    flex: 1
  },
  camera: {
    flex: 1
  },
  headerOverlay: {
    flexDirection: 'row',
    justifyContent: 'space-between',
    alignItems: 'center',
    paddingHorizontal: 20,
    paddingTop: 50,
    paddingBottom: 20
  },
  roundBtn: {
    width: 44,
    height: 44,
    borderRadius: 22,
    backgroundColor: 'rgba(255,255,255,0.2)',
    alignItems: 'center',
    justifyContent: 'center',
    backdropFilter: 'blur(10px)'
  },
  headerTitleContainer: {
    alignItems: 'center'
  },
  headerTitle: {
    color: '#FFF',
    fontSize: 18,
    fontWeight: 'bold'
  },
  aiStatus: {
    flexDirection: 'row',
    alignItems: 'center',
    marginTop: 4
  },
  aiDot: {
    width: 6,
    height: 6,
    borderRadius: 3,
    backgroundColor: '#4ade80',
    marginRight: 6
  },
  aiText: {
    color: 'rgba(255,255,255,0.8)',
    fontSize: 10,
    fontWeight: 'bold',
    letterSpacing: 1
  },
  guideContainer: {
    flex: 1,
    alignItems: 'center',
    justifyContent: 'center'
  },
  guideFrame: {
    width: width * 0.7,
    height: width * 0.7,
    borderWidth: 1,
    borderColor: 'rgba(255,255,255,0.3)',
    borderRadius: 24,
    position: 'relative'
  },
  corner: {
    position: 'absolute',
    width: 32,
    height: 32,
    borderColor: '#2c5926',
  },
  topL: { top: -2, left: -2, borderTopWidth: 4, borderLeftWidth: 4, borderTopLeftRadius: 20 },
  topR: { top: -2, right: -2, borderTopWidth: 4, borderRightWidth: 4, borderTopRightRadius: 20 },
  botL: { bottom: -2, left: -2, borderBottomWidth: 4, borderLeftWidth: 4, borderBottomLeftRadius: 20 },
  botR: { bottom: -2, right: -2, borderBottomWidth: 4, borderRightWidth: 4, borderBottomRightRadius: 20 },
  scanLine: {
    width: '100%',
    height: 2,
    backgroundColor: '#2c5926',
    shadowColor: '#2c5926',
    shadowOffset: { width: 0, height: 0 },
    shadowOpacity: 0.8,
    shadowRadius: 10,
    elevation: 10
  },
  tipsContainer: {
    paddingHorizontal: 20,
    marginBottom: 20
  },
  tipsCard: {
    backgroundColor: 'rgba(255,255,255,0.95)',
    borderRadius: 16,
    padding: 16,
    flexDirection: 'row',
    alignItems: 'center',
    shadowColor: '#000',
    shadowOffset: { width: 0, height: 4 },
    shadowOpacity: 0.2,
    shadowRadius: 12,
    elevation: 8
  },
  tipsIcon: {
    width: 36,
    height: 36,
    borderRadius: 10,
    backgroundColor: 'rgba(44, 89, 38, 0.1)',
    alignItems: 'center',
    justifyContent: 'center',
    marginRight: 12
  },
  tipsTextContent: {
    flex: 1
  },
  tipsTitle: {
    fontSize: 14,
    fontWeight: 'bold',
    color: '#111'
  },
  tipsBody: {
    fontSize: 12,
    color: '#666',
    marginTop: 2
  },
  gotItBtn: {
    backgroundColor: '#2c5926',
    paddingHorizontal: 16,
    paddingVertical: 8,
    borderRadius: 8,
    marginLeft: 12
  },
  gotItText: {
    color: '#FFF',
    fontSize: 12,
    fontWeight: 'bold'
  },
  controlsLayer: {
    paddingBottom: 40,
    paddingHorizontal: 32
  },
  controlsRow: {
    flexDirection: 'row',
    justifyContent: 'space-between',
    alignItems: 'center'
  },
  controlBtn: {
    alignItems: 'center'
  },
  controlIconCircle: {
    width: 52,
    height: 52,
    borderRadius: 26,
    backgroundColor: 'rgba(255,255,255,0.15)',
    alignItems: 'center',
    justifyContent: 'center',
    borderWidth: 1,
    borderColor: 'rgba(255,255,255,0.2)'
  },
  controlLabel: {
    color: '#FFF',
    fontSize: 10,
    marginTop: 6,
    fontWeight: '500'
  },
  captureOuter: {
    width: 84,
    height: 84,
    borderRadius: 42,
    backgroundColor: 'rgba(255,255,255,0.2)',
    alignItems: 'center',
    justifyContent: 'center'
  },
  captureMiddle: {
    width: 70,
    height: 70,
    borderRadius: 35,
    borderWidth: 3,
    borderColor: 'rgba(44, 89, 38, 0.3)',
    alignItems: 'center',
    justifyContent: 'center'
  },
  captureInner: {
    width: 58,
    height: 58,
    borderRadius: 29,
    backgroundColor: '#2c5926',
    alignItems: 'center',
    justifyContent: 'center',
    shadowColor: '#2c5926',
    shadowOffset: { width: 0, height: 4 },
    shadowOpacity: 0.4,
    shadowRadius: 10
  },
  bottomNavOverlay: {
    height: 80,
    backgroundColor: 'rgba(0,0,0,0.5)',
    flexDirection: 'row',
    justifyContent: 'space-around',
    alignItems: 'center',
    paddingBottom: 15,
    borderTopWidth: 1,
    borderTopColor: 'rgba(255,255,255,0.1)'
  },
  navItem: {
    alignItems: 'center'
  },
  navText: {
    color: 'rgba(255,255,255,0.6)',
    fontSize: 10,
    marginTop: 4
  },
  fullPreview: {
    flex: 1,
    backgroundColor: '#000'
  },
  previewImage: {
    width: '100%',
    height: '100%',
    opacity: 0.7
  },
  loadingOverlay: {
    ...StyleSheet.absoluteFillObject,
    alignItems: 'center',
    justifyContent: 'center',
    backgroundColor: 'rgba(0,0,0,0.4)'
  },
